INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Selective Forwarding Unit (SFU) architecture$q$, $q$Forwards WebRTC streams between participants without server-side mixing, keeping CPU load low for multi-party calls.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Multi-codec video support$q$, $q$Supports VP8, VP9, H.264 and AV1 with simulcast and Scalable Video Coding for adaptive quality under constrained bandwidth.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Built-in TURN server$q$, $q$Includes NAT traversal out of the box, removing the need for a separate external TURN service in most deployments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Session recording$q$, $q$Supports server-side recording of meetings for later playback.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$WHIP ingest protocol$q$, $q$Lets external encoders and streaming software publish video directly into a Galene group.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Administrative HTTP API$q$, $q$Allows scripted creation and management of groups and user accounts for large-scale provisioning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Native Android client$q$, $q$Dedicated mobile app with screen sharing, alongside full browser support on desktop and mobile.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Peer-to-peer file transfer and background blur$q$, $q$Built-in file sharing between participants plus client-side background blur for privacy.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Free and MIT-licensed, with full source code access and no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Very low CPU and RAM footprint compared to many comparable SFUs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Cross-platform server support across Linux, macOS, Windows and ARM devices$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Actively maintained with funded development and an independent security review$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Proven in production at major universities and open-source conferences$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$No official managed or hosted SaaS option; self-hosting is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Requires system administration skills to deploy and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$User interface is more minimal than commercial tools like Zoom or Google Meet$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Many-to-many meetings scale quadratically, limiting very large all-camera calls$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Smaller community and fewer integrations than Jitsi Meet$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Is Galene free?$q$, $q$Yes. Galene is MIT-licensed free and open-source software with no cost to download, run, or modify.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Who maintains Galene?$q$, $q$It is primarily maintained by Juliusz Chroboczek at IRIF, University of Paris Cite, with development currently funded by the NLnet Foundation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$How many participants can Galene handle?$q$, $q$As a rough guide, Galene supports about 300 participants per CPU core in one-to-many (lecture) scenarios and about 20 participants per core in many-to-many meetings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Does Galene have a mobile app?$q$, $q$Yes, there is a native Android client with screen sharing; iOS and other devices can join through a mobile browser.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$How does Galene compare to Jitsi Meet?$q$, $q$Both are open-source SFUs, but Galene is lighter-weight and simpler to deploy on modest hardware, while Jitsi has a larger ecosystem and more polished feature set.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Can I run Galene commercially?$q$, $q$Yes, the MIT licence permits commercial use, modification and redistribution without royalties.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$University lecture and remote examination platform$q$, $q$Originally built for and still used to deliver lectures, tutorials and supervised remote exams at Universite Paris Cite and Sorbonne Universite.$q$, $q$University IT departments and computer science faculties$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Conference and community event streaming$q$, $q$Used to host free-software and academic conferences such as LibrePlanet 2024 and JFLA 2021, letting organizers avoid proprietary conferencing platforms.$q$, $q$Open-source conference organizers and community groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Privacy-conscious self-hosted meetings$q$, $q$Deployed by organizations that want full control over meeting data and infrastructure instead of relying on a third-party video SaaS.$q$, $q$Privacy-focused organizations, NGOs and hackerspaces$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A - one-time download, self-hosted$q$, NULL, $q$["Full MIT-licensed source code","Unlimited groups and users when self-hosted","Built-in TURN server included","Community support via mailing list and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Galene is a free, open-source videoconferencing server built as a Selective Forwarding Unit (SFU), meaning it relays WebRTC audio and video streams between participants rather than mixing them, which keeps server load low for multi-party calls.$q$, $q$Created in 2020 by researcher Juliusz Chroboczek at IRIF (Universite Paris Cite) to support remote lectures and exams during the COVID-19 lockdown, Galene has since been used in production at Universite Paris Cite, Sorbonne Universite, and events like LibrePlanet 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Galene supports VP8, VP9, H.264 and AV1 codecs with simulcast and Scalable Video Coding, a built-in TURN server, server-side recording, screen sharing, background blur, peer-to-peer file transfer and WHIP protocol ingest.$q$, $q$An administrative HTTP API lets operators script group and user provisioning, while a native Android client and full browser support cover desktop and mobile use cases without requiring any plugins.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Galene is entirely free under the MIT licence; there are no subscription tiers, seat fees, or usage limits when self-hosted, and the source code can be modified freely, including for commercial deployments.$q$, $q$The only real costs are server hardware and administrator time. Ongoing development is funded through public-interest programs such as NLnet's NGI Zero Core rather than customer revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36449a40-80e5-4dd6-8164-c731f720d4dd', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Recipe management and standardization$q$, $q$Centralizes recipe data so it can be documented once and reused consistently across a kitchen or organization.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Automated menu and recipe costing$q$, $q$Ties live ingredient prices to recipes and menus so margin impact from supplier price changes is visible in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Allergen and nutrition tracking$q$, $q$Automates allergen disclosure and nutrition data, particularly valuable for regulated institutional foodservice.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Recipe scaling$q$, $q$Automatically recalculates ingredient quantities for different batch sizes and plating formats.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Inventory and purchasing integration$q$, $q$Connects recipe and menu data to purchasing and inventory workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Production planning$q$, $q$Helps kitchens plan production runs based on recipe and demand data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Multi-unit recipe rollout$q$, $q$Supports standardizing recipes and menus across multiple restaurant locations or brands.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$API and system integrations$q$, $q$Connects with existing POS and accounting systems to keep data synchronized.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Centralizes recipe, cost and allergen data across chefs, operators and dietitians in one system$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Real-time costing helps catch margin erosion from supplier price changes quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Backed by significant venture funding (about 20 million dollars) from Astanor Ventures and Zetta Venture Partners$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Strong customer traction, with more than 150,000 recipes and 5 million-plus meals served on the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Highly rated by users on review platforms like Capterra$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$No public pricing; requires a sales demo to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Smaller company than large incumbents like CrunchTime, which may mean a narrower support and integration footprint$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Standardizing legacy recipe data during onboarding can take significant time and effort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Primarily geared toward mid-market and enterprise operators, less turnkey for single independent restaurants$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$What is Galley Solutions?$q$, $q$Galley Solutions is a culinary resource planning platform that centralizes recipe, menu costing, allergen and nutrition data for restaurants and other commercial kitchens.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$How much does Galley cost?$q$, $q$Galley uses custom, quote-based pricing; prospective customers must book a demo to receive pricing tailored to their number of locations and users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Who founded Galley Solutions and when?$q$, $q$Galley was founded in 2017 by Ian Christopher Brigden and Benji Koltai in San Diego, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$How much funding has Galley raised?$q$, $q$Galley has raised about 20 million dollars in total funding, including a 14.2 million dollar Series A led by Astanor Ventures with participation from Zetta Venture Partners, completed in May 2022.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Who uses Galley?$q$, $q$Chefs, multi-unit restaurant operators, catering companies, and institutional foodservice teams such as hospital and school dietitians; the company reports over 150,000 recipes and 5 million-plus meals served through the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$What are alternatives to Galley?$q$, $q$Notable alternatives include MarginEdge, Apicbase, CrunchTime, meez and MarketMan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Multi-unit restaurant recipe standardization$q$, $q$Helps restaurant groups keep recipes, costs and preparation methods consistent across many locations.$q$, $q$Multi-location restaurant groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Institutional foodservice nutrition compliance$q$, $q$Automates allergen and nutrition tracking for regulated environments like hospitals and schools.$q$, $q$Hospital and school dietitians and foodservice directors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Menu costing and margin control$q$, $q$Gives culinary and finance teams real-time visibility into recipe-level food costs and margins.$q$, $q$Executive chefs and culinary operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$Custom / Enterprise$q$, $q$Contact for pricing$q$, $q$Custom (annual contract, quote-based)$q$, NULL, $q$["Recipe management and standardization","Menu and recipe costing","Allergen and nutrition tracking","Production planning tools","Dedicated onboarding and demo"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Galley Solutions is a culinary resource planning platform that centralizes recipe, menu, costing, allergen and nutrition data for restaurants, catering companies and institutional foodservice operators.$q$, $q$Founded in 2017 in San Diego by Ian Christopher Brigden and Benji Koltai, Galley has raised about 20 million dollars including a 14.2 million dollar Series A led by Astanor Ventures, and reports over 150,000 recipes created and 5 million-plus meals served on the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers recipe management and scaling, automated menu and recipe costing, allergen and nutrition tracking, and production planning tools designed for chefs, operators and dietitians working from shared data.$q$, $q$It also supports purchasing and inventory integration, multi-unit recipe rollout for restaurant groups, and API-based integrations with existing POS and accounting systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Galley does not publish self-serve pricing; prospective customers request a demo and receive a custom quote based on the number of locations, recipes and users involved.$q$, $q$This sales-led pricing model is typical for mid-market and enterprise foodservice software and reflects Galley's focus on multi-location operators rather than single-location independent restaurants.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('81547fe6-0936-48d6-be6a-e999e7dcc1ec', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Web-based server management$q$, $q$Install, start, stop and restart game servers from a browser dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Remote console access$q$, $q$Send RCON commands and view live console output without needing SSH access.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Built-in file manager$q$, $q$Edit server files and extract archives directly from the web interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Task scheduler$q$, $q$Automates restarts, updates and backups on daily, hourly or custom intervals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Granular per-server permissions$q$, $q$Assigns fine-grained user access controls on a per-server basis.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$REST API and WebSocket events$q$, $q$Provides documented API access and real-time events for building custom integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$WASM plugin architecture$q$, $q$Extends the panel using Go, Rust, C++, Python or any WASM-compilable language.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Multi-database support$q$, $q$Works with PostgreSQL, MySQL, SQLite or an in-memory database backend.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Very lightweight; runs as a native binary without Docker overhead$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Flexible WASM-based plugin architecture supporting multiple languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Cross-platform support for Linux, Windows Server and macOS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Active development with frequent releases on GitHub$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Smaller community and GitHub star count than newer competitors like Pterodactyl or Pelican$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Documentation and community support historically skew toward Russian-language and Eastern European users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$No official managed or hosted cloud version; self-hosting is required$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Initial setup involving panel, daemon and gRPC communication is more involved than a fully managed alternative$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Is GameAP free?$q$, $q$Yes, GameAP is released under the MIT license and is free to download, run, and modify, including for commercial use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$What games does GameAP support?$q$, $q$GameAP supports many dedicated game servers including Minecraft, Counter-Strike 2, Rust and Grand Theft Auto V, among others configurable via its game definitions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$How is GameAP different from Pterodactyl?$q$, $q$GameAP runs as a native binary without requiring Docker containers, aiming for lower resource overhead, while Pterodactyl is built around per-server Docker containerization.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$What tech stack powers GameAP?$q$, $q$GameAP's backend is written primarily in Go, its frontend uses Vue.js, and the panel communicates with a lightweight daemon over gRPC.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Can I extend GameAP with plugins?$q$, $q$Yes, GameAP supports a WebAssembly-based plugin system that lets developers write extensions in Go, Rust, C++, Python or other WASM-compilable languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Who maintains GameAP?$q$, $q$GameAP is maintained by an open-source community originally started by developer et-nik (Nikita Kuznetsov), with current development at the gameap organization on GitHub.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Hosting providers running many game servers$q$, $q$Lets hosting companies manage large fleets of game servers with low resource overhead and white-label control.$q$, $q$Game server hosting companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Community and clan server management$q$, $q$Gives gaming communities a browser-based way to manage their own Minecraft or Counter-Strike 2 servers.$q$, $q$Gaming communities and clan administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Self-hosted home lab game servers$q$, $q$Allows hobbyists to run and manage several game servers on a home server or budget VPS.$q$, $q$Hobbyist self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT license","Unlimited game servers on your own hardware","REST API and WebSocket access","Community support on GitHub and Patreon"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GameAP is a free, open-source, self-hosted web panel for installing, configuring and monitoring game servers such as Minecraft, Counter-Strike 2, Rust and Grand Theft Auto V.$q$, $q$Its roots trace to a PHP-based panel started around 2013-2014 by developer et-nik; the modern GameAP is a full Go rewrite distributed under the MIT licence, positioned as an alternative to Pterodactyl and Pelican.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GameAP runs as a native binary without requiring containers, supporting thousands of servers per node with a REST API, WebSocket events, a file manager and an RCON-based remote console.$q$, $q$A WebAssembly plugin architecture lets developers extend the panel in Go, Rust, C++, Python or any WASM-compilable language, alongside granular per-server user permissions and a task scheduler for automated maintenance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GameAP is completely free under the MIT licence, with no tiers, seat limits, or feature gating; source code can be freely modified and redistributed, including commercially by hosting providers.$q$, $q$The only costs are the server hardware GameAP runs on. Development is community-supported through GitHub contributions and an optional Patreon page.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ebf3f796-8c8b-4d07-a8cf-8d19e32204e3', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Automatic library scanning$q$, $q$Scans configured folders and automatically fetches metadata and cover art for each game.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Web-based browsing and download$q$, $q$Provides a clean browser interface for browsing and directly downloading games in the library.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Library sharing$q$, $q$Allows multiple users, such as family or friends, to share access to one game library.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$LAN-optimized caching$q$, $q$Caches data locally to speed up repeated downloads over a home network.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Single sign-on support$q$, $q$Integrates with OAuth2 and OpenID Connect identity providers such as Authentik and Pocket-ID.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Plugin architecture$q$, $q$Uses the PF4J framework to let developers extend Gameyfin without modifying the core codebase.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Colorblind-accessible themes$q$, $q$Includes UI themes designed with accessibility in mind.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Docker and Unraid deployment$q$, $q$Ships official Docker images and an Unraid Community Applications listing for simple installation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Completely free and open source with no paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Actively developed, with over 40 releases and a growing GitHub community$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Modern tech stack (Spring Boot, Kotlin, React, TypeScript)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Simple deployment via Docker or Unraid$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Supports self-hosted single sign-on integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Relatively young project (launched 2023), so some features and polish are still evolving$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$AGPL-3.0 license imposes copyleft obligations on modified redistributions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Requires users to already own the games they index; does not source game files itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Smaller plugin and integration ecosystem than established media servers like Jellyfin or Plex$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Is Gameyfin free?$q$, $q$Yes, Gameyfin is fully free and open source under the AGPL-3.0 license with no paywalls.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$What platforms does Gameyfin run on?$q$, $q$Gameyfin runs via Docker, on Unraid, or on any system with a Java Virtual Machine, covering Linux, Windows and macOS hosts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Does Gameyfin download games for me?$q$, $q$No, Gameyfin indexes and serves games you already own and have placed in your library folders; it does not source or distribute game content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Can multiple people share one Gameyfin library?$q$, $q$Yes, Gameyfin supports multi-user access so a library can be shared with friends or family.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$How does Gameyfin compare to Jellyfin or Plex?$q$, $q$Jellyfin and Plex are media servers for video and music; Gameyfin applies the same self-hosted library concept specifically to PC game files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Does Gameyfin support single sign-on?$q$, $q$Yes, through OAuth2 and OpenID Connect, with documented support for providers like Authentik and Pocket-ID.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Personal PC game library organization$q$, $q$Helps a single user browse and manage a large local game collection from any device.$q$, $q$PC gamers with large local game collections$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Family or household game sharing$q$, $q$Lets multiple household members access a shared game library from a home server or NAS.$q$, $q$Households sharing a NAS or home server$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Self-hosted alternative to cloud launchers$q$, $q$Gives privacy-focused users a self-hosted way to browse owned games without relying on platform cloud libraries.$q$, $q$Privacy-focused self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full AGPL-3.0 licensed source code","Unlimited library size on your own hardware","Multi-user sharing","Plugin support and SSO integration"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gameyfin is a free, open-source, self-hosted application that scans local folders of PC games, fetches metadata and cover art, and serves the result as a browsable web library, similar to how Jellyfin works for movies and TV.$q$, $q$Led by developer grimsi and first released in 2023, the project has grown quickly, reaching over 40 releases, version 2.4.0, and more than 1,000 GitHub stars by mid-2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gameyfin automatically indexes game libraries, supports direct in-browser downloads, and lets users share collections with other household members, with LAN-optimized caching for fast local transfers.$q$, $q$It supports single sign-on via OAuth2 and OpenID Connect providers like Authentik and Pocket-ID, a PF4J-based plugin system, and colorblind-accessible themes, and deploys easily via Docker or Unraid.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gameyfin is completely free and open source under the AGPL-3.0 licence, with no paywalls, subscription tiers, or feature restrictions of any kind.$q$, $q$The only cost is the hardware used to self-host it, such as an existing home server or NAS most users already own.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('615af08e-8dd3-4316-8837-e9ead4f24aa4', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Amazon S3 API compatibility$q$, $q$Supports multipart uploads, presigned URLs, bucket policies, CORS and versioning for drop-in compatibility with S3 tooling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Dynamo-style consistent hashing$q$, $q$Distributes data across nodes using a hashing ring inspired by Amazon's Dynamo system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$CRDT-based consistency$q$, $q$Reconciles state between nodes without a consensus protocol, avoiding bottlenecks under high latency.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Geo-distributed replication$q$, $q$Designed to replicate data across nodes in different physical locations and stay available if some are unreachable.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Single dependency-free binary$q$, $q$Ships as one static Rust binary with no external database or orchestration required.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Low hardware requirements$q$, $q$Runs on as little as 1GB RAM and 16GB disk, supporting older or secondhand machines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Broad ecosystem compatibility$q$, $q$Works with Nextcloud, Matrix, Mastodon, PeerTube, rclone, restic and other S3-compatible tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$High failure resilience$q$, $q$Built to tolerate node, disk and network failures without losing availability.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Free and open source under AGPLv3 with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Genuinely lightweight; runs on secondhand or low-power hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Purpose-built for geo-distributed, non-datacenter deployments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Avoids consensus bottlenecks through a CRDT-based design$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Backed by public research funding rather than venture capital, aligning incentives with users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Not a fully managed service; requires self-hosting and cluster administration$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Smaller ecosystem and less commercial support than AWS S3, MinIO or Backblaze B2$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Best suited to small-to-medium scale rather than hyperscale storage needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$AGPLv3 licensing can be a blocker for some commercial redistribution use cases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Is Garage really S3-compatible?$q$, $q$Yes, it implements the core Amazon S3 REST API including multipart uploads, presigned URLs, CORS and bucket policies, so most existing S3 clients work unmodified.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Who builds and maintains Garage?$q$, $q$The Deuxfleurs association, a French collective of self-hosting enthusiasts and researchers, originally founded by PhD students including Alex Auvolat and Quentin Dufour.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$How is Garage funded?$q$, $q$Through European public research funding programs including NGI POINTER, NLnet's NGI0 Entrust, and the NGI0 Commons Fund, between 2021 and 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$What hardware does Garage need?$q$, $q$As little as 1GB RAM and 16GB disk per node, running on x86_64, ARMv7 or ARMv8 CPUs, including older or secondhand machines.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$What applications work with Garage?$q$, $q$Nextcloud, Matrix, Mastodon, PeerTube, rclone and any other S3-API-compatible software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$How does Garage differ from MinIO?$q$, $q$Garage is purpose-built for small, geographically distributed clusters with high network latency tolerance and CRDT-based consistency, while MinIO focuses more on high-performance, low-latency data center deployments.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Self-hosted backup target$q$, $q$Provides an S3-compatible destination for backup tools like restic and rclone across low-cost servers.$q$, $q$Self-hosters and small IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Storage backend for federated apps$q$, $q$Serves as the object storage layer for federated services such as Mastodon, Matrix and PeerTube.$q$, $q$Fediverse and federated service operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Geo-redundant community storage$q$, $q$Lets non-profits and collectives replicate data across volunteer or donated hardware in different locations.$q$, $q$Non-profits and community tech collectives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full AGPLv3 licensed source code","S3 API compatibility","Unlimited nodes and storage on your own hardware","Community documentation and chat support channels"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Garage is a free, open-source, S3-compatible object storage system built by the Deuxfleurs association and released for production use starting in 2020, purpose-built for small, geographically distributed self-hosted clusters.$q$, $q$Unlike storage systems designed for a single data center, Garage uses Dynamo-style consistent hashing and CRDTs so nodes can handle requests independently even under high inter-node latency, avoiding the consensus bottlenecks of Raft-based systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Garage implements the core Amazon S3 REST API, including multipart uploads, presigned URLs, bucket policies, CORS and versioning, making it a drop-in backend for tools like Nextcloud, Matrix, Mastodon and PeerTube.$q$, $q$It ships as a single dependency-free Rust binary that runs on as little as 1GB of RAM and supports heterogeneous or secondhand x86_64, ARMv7 and ARMv8 hardware.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Garage is free and open source under the AGPLv3 license, with no company, subscription or licensing fee behind it; anyone can run it at zero cost beyond their own hardware.$q$, $q$Development has instead been funded through European public research programs such as NGI POINTER and NLnet's NGI0 Entrust and Commons Fund initiatives.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3be3e9b4-cb50-43f7-9445-28dcf621ad49', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Automated review generation$q$, $q$Sends email and SMS requests to customers, routing feedback based on sentiment toward public reviews or private resolution.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$100-plus review site monitoring$q$, $q$Tracks new reviews across major platforms and industry-specific directories from one dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$NPS surveys$q$, $q$Measures and tracks Net Promoter Score and customer sentiment over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$AI-generated review responses$q$, $q$Suggests AI-assisted replies to incoming reviews to save staff time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Review widgets and social sharing$q$, $q$Automates redistribution of positive reviews as marketing content and website widgets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$QR codes and feedback links$q$, $q$Captures feedback in physical locations via custom links and QR codes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Listings Hub add-on$q$, $q$Syncs business name, address and phone information across roughly 125 online directories.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Review Defense add-on$q$, $q$Detects and helps dispute fraudulent or policy-violating reviews.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Broad review-site coverage across more than 100 platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$AI-assisted review responses save time for busy teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Flexible multi-location and white-label agency pricing options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Established player since 2013, backed by Traject's marketing-technology portfolio$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Strong built-in reporting and NPS survey tooling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Entry pricing of 99 dollars per month is high for a solo small business compared to some lighter competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Add-ons like Listings Hub and Review Defense cost extra on top of base plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Per-location multi-site pricing can add up quickly for large franchise groups$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Some pricing and plan details require a sales quote rather than being fully self-serve$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$How much does GatherUp cost?$q$, $q$Plans start around 99 dollars per month for a single location, with multi-location pricing around 60 dollars per location per month depending on volume, and custom Agency pricing for white-label resellers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Who owns GatherUp?$q$, $q$GatherUp was founded in 2013 and acquired by Traject, a marketing-technology holding company, in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Does GatherUp offer a free trial?$q$, $q$Yes, a 14-day free trial is commonly offered to prospective customers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$What review sites does GatherUp monitor?$q$, $q$More than 100 review sites, including major platforms like Google and Facebook plus industry-specific directories.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Does GatherUp support SMS review requests?$q$, $q$Yes, plans include monthly SMS and email credits, with an additional SMS marketing add-on available.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$What are alternatives to GatherUp?$q$, $q$Notable alternatives include Birdeye, Podium, Reputation.com, Grade.us and Yext.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Single-location review generation$q$, $q$Automates review requests and feedback collection for one location.$q$, $q$Independent local businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Multi-location reputation management$q$, $q$Centralizes reporting and review monitoring across dozens or hundreds of locations.$q$, $q$Franchise and multi-location marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$White-label reputation management for agencies$q$, $q$Lets agencies resell reputation management services to their own clients under their own branding.$q$, $q$Marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Small Business$q$, $q$$99/month$q$, $q$Monthly, annual discount available$q$, NULL, $q$["1 location","100+ review site monitoring","NPS surveys","AI-generated review responses","300 SMS and 3,000 email credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Multi-Location$q$, $q$From $60/month per location$q$, $q$Monthly, tiered pricing for 2-10+ locations$q$, NULL, $q$["Volume pricing for 2-100+ locations","Centralized multi-location reporting","Review widgets and social sharing","API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$Agency$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["White-label reputation management for clients","Client account management","Custom branding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GatherUp is a customer feedback and reputation management platform founded in San Jose in 2013 and acquired by Traject in 2019, helping local businesses and multi-location brands collect reviews and monitor their online reputation.$q$, $q$The platform routes customer feedback through automated requests, directing happy customers toward public reviews and unhappy customers into a private resolution loop, while monitoring more than 100 review sites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include automated email and SMS review requests, NPS surveys, AI-generated review response suggestions, QR codes and feedback links, and review widgets for social sharing.$q$, $q$Paid add-ons extend the platform further, including Listings Hub for business-listing syncing across roughly 125 directories and Review Defense for detecting and disputing fraudulent reviews.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GatherUp starts at 99 dollars per month for a single location on the Small Business plan, with a 14-day free trial commonly offered.$q$, $q$Multi-location pricing drops to roughly 60 dollars per location per month for 2-10 locations, with further volume discounts at scale, plus a custom-quoted white-label Agency plan for resellers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb4b68ba-b4d4-4c0f-8fd7-b849bda16445', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Multi-protocol health checks$q$, $q$Monitors HTTP/HTTPS, ICMP, TCP, DNS, WebSocket, gRPC, SSH, STARTTLS, TLS and GraphQL endpoints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Condition-based evaluation$q$, $q$Evaluates checks against configurable conditions such as status code, response time, body content and certificate expiry.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$40-plus alerting integrations$q$, $q$Sends alerts to Slack, Teams, Discord, PagerDuty, Twilio, Datadog and other providers out of the box.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$YAML-based configuration$q$, $q$Defines the entire monitoring setup as version-controllable YAML with environment variable interpolation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Public status pages$q$, $q$Publishes uptime and response-time badges and public-facing status dashboards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Suites for workflow checks$q$, $q$Runs sequential, multi-step checks to verify end-to-end flows like a login process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$External Endpoints$q$, $q$Lets agents behind private networks push their status into a central Gatus instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Prometheus metrics export$q$, $q$Exports monitoring data in Prometheus format for existing observability stacks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Free, unlimited-endpoint self-hosted option under the Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Very lightweight and inexpensive to self-host$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Huge range of built-in alert integrations (40-plus)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Simple, version-controllable YAML configuration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Large, active GitHub community with 10,000-plus stars$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Self-hosted version requires running and maintaining your own infrastructure$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Managed gatus.io plans add cost on top of the otherwise-free core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$UI and enterprise features like SSO and advanced role-based access are less mature than dedicated commercial status-page vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Documentation is community-maintained and can lag behind the newest features$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Is Gatus free?$q$, $q$The core Gatus project is free and open source under the Apache 2.0 license and can be self-hosted at no cost; gatus.io also offers a paid managed hosting option for teams that do not want to run their own infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Who created Gatus?$q$, $q$It was created and is primarily maintained by a developer known as TwiN, with contributions from the open-source community.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$What can Gatus monitor?$q$, $q$HTTP/HTTPS endpoints, ICMP ping, TCP ports, DNS records, WebSocket, gRPC, SSH, TLS/STARTTLS certificate expiry and GraphQL endpoints.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$How is Gatus different from Uptime Kuma?$q$, $q$Both are open-source, self-hosted monitoring tools; Gatus is configuration-file (YAML) driven and Go-based, while Uptime Kuma emphasizes a fully UI-driven setup.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Does Gatus support Kubernetes?$q$, $q$Yes, it can be deployed via Docker, Kubernetes Helm charts, or Terraform, in addition to a plain binary.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Can Gatus send alerts to Slack or PagerDuty?$q$, $q$Yes, alongside 40-plus other providers including Teams, Discord, Twilio and custom webhooks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Internal service and API uptime monitoring$q$, $q$Actively checks internal services and APIs and alerts engineering teams when they fail.$q$, $q$DevOps and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Public status pages for SaaS products$q$, $q$Gives SaaS companies a way to communicate uptime and incidents to customers.$q$, $q$SaaS companies communicating uptime to customers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Home lab infrastructure monitoring$q$, $q$Lets self-hosting hobbyists monitor personal servers and services for free.$q$, $q$Self-hosting hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Apache 2.0 licensed source code","Unlimited endpoints and alert rules","40+ alerting integrations","Prometheus metrics export"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$Gatus.io Managed$q$, $q$Contact gatus.io for current pricing$q$, $q$Monthly/Annual$q$, NULL, $q$["Hosted status pages with no infrastructure to manage","Managed monitoring dashboard","Account-based plan tiers"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gatus is a developer-oriented health dashboard and status page tool, maintained as a free, open-source project since 2019 by a developer known as TwiN, with a managed cloud version also offered at gatus.io.$q$, $q$It actively probes HTTP, TCP, DNS, ICMP, WebSocket, gRPC, SSH and TLS endpoints on a schedule and evaluates configurable conditions to determine health, rather than passively observing real traffic.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gatus supports more than 40 alerting integrations including Slack, Teams, Discord, PagerDuty and Twilio, along with Prometheus metrics export and public or internal status pages.$q$, $q$Advanced features include Suites for sequential workflow checks, External Endpoints for agents behind private networks, and Announcements for posting incident updates directly to a status page.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted core of Gatus is free under the Apache 2.0 license, with unlimited endpoints and alert rules; typical self-hosting costs run only a few dollars a month on platforms like Railway.$q$, $q$Gatus.io offers a managed cloud version with a free exploration tier and paid account plans for teams that want a hosted status page without running their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a647c355-aedc-4b4f-b8fd-c2ffd96f3b9a', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Talent sourcing CRM$q$, $q$Gives recruiters access to a database of more than 800 million candidate profiles for proactive sourcing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Multi-channel automated outreach$q$, $q$Launches personalized, multi-step email outreach sequences to candidates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Applicant tracking system$q$, $q$Manages job requisitions, application review, interview feedback and offers, natively or alongside an existing ATS.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Interview scheduling$q$, $q$Provides a self-service candidate scheduling portal with automated interviewer load balancing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Pipeline analytics and benchmarking$q$, $q$Delivers funnel dashboards, hiring forecasts and industry benchmark comparisons for TA leaders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$AI sourcing and ranking agents$q$, $q$Uses AI to suggest, rank and rediscover candidates for open roles.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$LinkedIn, Gmail and Outlook integration$q$, $q$Integrates directly with LinkedIn Recruiter and email clients via a browser extension.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Flexible deployment model$q$, $q$Works alongside an existing ATS like Greenhouse or Lever, or as an all-in-one replacement.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Deep integration with LinkedIn Recruiter, Gmail and Outlook streamlines sourcing workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Strong analytics and benchmarking for measuring recruiting performance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Flexible deployment; can sit alongside an existing ATS or replace it entirely$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Well-funded (148 million dollars raised) with enterprise customers like Wayfair, Dropbox, Cisco and DoorDash$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Discounted startup pricing tier lowers the barrier for small companies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Full pricing is largely custom and quote-based rather than transparent for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$AI-powered features require a separate, likely pricier seat tier on top of standard seats$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Can be more sourcing and CRM-focused than some all-in-one competitors like Ashby$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Best value is realized at scale, so very small non-startup teams may find it costly relative to lighter tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Who founded Gem and when?$q$, $q$Gem was founded in 2017 by Steven Bartel and Nick Bushak, both former engineering managers at Dropbox and Facebook.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$How much funding has Gem raised?$q$, $q$Gem has raised a total of 148 million dollars, including a 100 million dollar Series C in September 2021 led by ICONIQ Growth at a 1.2 billion dollar valuation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$How much does Gem cost?$q$, $q$Pricing is largely custom based on company size and chosen deployment; a discounted startup tier starts around 130 dollars per month for companies with 1-10 employees, with additional discounts for companies under 30 or 30-100 employees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Does Gem replace my existing ATS?$q$, $q$It can either integrate alongside an existing ATS like Greenhouse or Lever, or serve as a full all-in-one ATS and CRM replacement.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$What companies use Gem?$q$, $q$Enterprise customers include Wayfair, Dropbox, Nasdaq, Cisco and DoorDash, among more than 1,200 talent acquisition teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$What are the main alternatives to Gem?$q$, $q$Ashby, Greenhouse, Lever, hireEZ, SeekOut and Beamery.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Proactive candidate sourcing at scale$q$, $q$Helps recruiters build and manage large outbound sourcing pipelines with CRM-style tracking.$q$, $q$Technical and executive recruiters and sourcers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Recruiting analytics and forecasting$q$, $q$Gives talent acquisition leadership visibility into pipeline health, forecasts and benchmarks.$q$, $q$Talent acquisition leaders and recruiting operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Lean startup hiring$q$, $q$Provides discounted access to sourcing, ATS and analytics tools for early-stage companies.$q$, $q$Early-stage startups with 1-100 employees$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Startup$q$, $q$$130/month (discounted from $270/month)$q$, $q$Monthly, 10% discount if billed annually$q$, NULL, $q$["For companies with 1-10 employees","AI sourcing and CRM","Analytics","Scheduling","ATS"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Standard Seat$q$, $q$Custom pricing$q$, $q$Annual contract, per seat$q$, NULL, $q$["Sourcing and email-finding tools","ATS workflows","Candidate management","Standard integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$AI-Powered Seat$q$, $q$Custom pricing$q$, $q$Annual contract, per seat$q$, NULL, $q$["AI sourcing agents","AI application review","Talent rediscovery and ranking","All Standard Seat features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom annual contract$q$, NULL, $q$["Gem All-in-One or Gem plus existing ATS","Advanced analytics and benchmarking","Dedicated support and onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gem is an AI-powered recruiting CRM and applicant tracking platform founded in 2017 by former Dropbox and Facebook engineering managers Steven Bartel and Nick Bushak, headquartered in San Francisco.$q$, $q$The company has raised 148 million dollars in total funding, including a 100 million dollar Series C in 2021 at a 1.2 billion dollar unicorn valuation, and now serves more than 1,200 talent acquisition teams including Wayfair, Dropbox, Cisco and DoorDash.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gem combines sourcing and CRM tools backed by more than 800 million candidate profiles, applicant tracking, interview scheduling with load balancing, and pipeline analytics and benchmarking for talent acquisition leaders.$q$, $q$Newer AI-powered features include AI sourcing agents, AI-assisted application review, and talent rediscovery that resurfaces previously sourced candidates for new openings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ade06e5-b645-47e5-8350-a2890ac101e4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gem uses largely custom, per-seat pricing that varies by company size and deployment model, distinguishing between Standard Seats and AI-Powered Seats.$q$, $q$The one public pricing point is a startup tier at 130 dollars per month for companies with 1-10 employees, with additional discounts, including up to six months free, for companies under 30 or 30-100 employees.$q$]::text[], 2);
