-- Enrichment marathon batch: Galene, Galley, GameAP, Gameyfin, Garage, GatherUp, Gatus, Gem

-- ── Galene ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Galene is a free and open-source, self-hosted WebRTC videoconferencing server (a Selective Forwarding Unit) built in Go, designed to run multi-party video meetings, lectures and conferences on modest server hardware.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France (IRIF, Universite Paris Cite)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Galene Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Galene is a free, self-hosted WebRTC video server (SFU) built in Go. Explore its features, MIT license, architecture, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Galene is a self-hosted videoconferencing server that falls into the category of software known as a Selective Forwarding Unit, or SFU: rather than mixing audio and video streams on the server the way an MCU does, it forwards individual WebRTC streams from each participant to the others, which keeps CPU usage low while still allowing many-to-many video calls. The project was started in the spring of 2020 by Juliusz Chroboczek, a researcher at IRIF (the computer science research lab of Universite Paris Cite), during the first COVID-19 lockdown in France. The immediate motivation was practical rather than commercial: the Department of Computer Science needed a way to run lectures, tutorials and even remote examinations online, and existing options at the time were either proprietary, resource-hungry, or both. By December 2020 the software had matured enough to be released as free and open-source software under the MIT licence, and it has been in continuous production use at Universite Paris Cite and Sorbonne Universite ever since, alongside appearances at academic and community events such as SOCS 2020, JFLA 2021 and LibrePlanet 2024. Architecturally, Galene's server is written in Go and built on the Pion implementation of WebRTC, a pure-Go media stack. This gives Galene excellent portability: the server runs on Linux (amd64, arm64 and armv7), on OpenWRT-class MIPS routers, on macOS and on Windows, and it ships as a single, dependency-light binary that is simple to deploy without containers or complex orchestration. The default web client is plain JavaScript and works in all current desktop and mobile browsers without a plugin, while a native Android client is also available for users who want screen sharing and a more integrated mobile experience. On the media side, Galene supports the VP8, VP9, H.264 and AV1 video codecs, simulcast and Scalable Video Coding (SVC) for adaptive quality under constrained bandwidth, a built-in TURN server for NAT traversal, server-side recording, background blur in the client, peer-to-peer file transfer between participants, and support for the WHIP ingest protocol so external encoders and streaming tools can publish directly into a Galene group. An administrative HTTP API allows operators to script the creation and management of groups and user accounts, important for institutions that need to provision many course sections or meeting spaces automatically. Resource efficiency is a defining characteristic and a large part of why Galene has found a niche among self-hosters, universities and privacy-conscious organizations. According to the project's documentation, a typical 100-person lecture requires only about a quarter of a CPU core, and the software can sustain roughly 300 simultaneous participants per core in a one-to-many pattern. Many-to-many meetings, where every participant sends and receives every other participant's video, scale quadratically rather than linearly, so Galene's practical ceiling there is closer to about 20 participants per core, a limitation shared by essentially every SFU-based system rather than something unique to Galene. Because Galene is free, open-source software rather than a company, there is no subscription, no per-seat pricing and no vendor lock-in: anyone can download the source from GitHub, compile or run the provided binary, and operate their own instance indefinitely at zero licensing cost. Development has been supported at different points by Nexedi (between September 2020 and February 2021) and, since June 2024, by the NLnet Foundation's NGI Zero Core programme, which funds public-interest internet infrastructure. The codebase has also undergone an independent security review by Radically Open Security, funded through NLnet, a meaningful trust signal for institutions considering it for sensitive use cases like exams or confidential meetings. Galene's natural competitors are other self-hostable, open-source videoconferencing systems, most notably Jitsi Meet and BigBlueButton, and to a lesser extent OpenVidu and custom mediasoup-based deployments. Compared with Jitsi, which is the most widely deployed alternative and backed by 8x8, Galene is deliberately smaller in scope: it does not attempt to be a full-featured meeting product with breakout rooms, calendar integrations, or a polished commercial UI, and instead focuses on being lightweight, auditable and easy to run on a single low-cost server. This makes it attractive to system administrators at universities, hackerspaces, NGOs and free-software-aligned organizations who want a videoconferencing tool they can fully understand and control, but it is a poorer fit for organizations wanting a managed, support-backed SaaS product with enterprise features like SSO federation or compliance certifications, since there is no company behind Galene to sell them. The target audience, in short, is technically capable self-hosters: university IT departments running lecture and exam infrastructure, free-software communities and conferences, small-to-medium organizations that already run their own servers for privacy or cost reasons, and individual power users comfortable with command-line deployment. It is less suited to non-technical end users looking for a one-click hosted meeting link, since standing up a Galene instance requires basic server administration, DNS and TLS configuration, and capacity planning around the CPU-per-participant guidance above. For the audience it does serve, Galene offers a rare combination in the videoconferencing space: genuinely low resource requirements, a permissive licence, funded development, and a track record of real production use at scale in academic settings.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '36449a40-80e5-4dd6-8164-c731f720d4dd';

