-- ── GatherUp ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$GatherUp is a customer feedback and online reputation management platform that helps local businesses and multi-location brands collect reviews, run NPS surveys and monitor their presence across 100-plus review sites.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$99/month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$GatherUp Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GatherUp is a review and reputation management platform for local businesses. See 2026 pricing plans, features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GatherUp is a customer feedback, reviews and online reputation management platform aimed at local businesses, multi-location brands and the marketing agencies that serve them. Founded in San Jose, California in 2013 by a group of local search marketers, the company built its product around a straightforward but high-value workflow for local businesses: systematically ask customers for feedback right after a purchase or service interaction, route happy customers toward public reviews on sites like Google, and route unhappy customers into a private feedback loop the business can resolve before it becomes a public one-star review. In 2019, GatherUp was acquired by Traject, a marketing-technology holding company now headquartered in Austin, Texas, that also owns other local-marketing and social-media tools including Grade.us, Loomly, PLANOLY and Sendible. Under Traject's ownership, GatherUp has continued to operate as a distinct product and brand rather than being folded into a combined suite, and reported employee counts for the GatherUp team specifically range from roughly half a dozen to a few dozen depending on the data source, consistent with a mature, profitable product line inside a larger portfolio company rather than an independently scaling venture-funded startup. The core of GatherUp's platform is review and feedback generation: automated email and SMS requests sent to customers, configurable to route feedback based on sentiment, paired with monitoring across more than 100 review sites so a business can see, and via AI-assisted response suggestions reply to, new reviews as they appear across Google, Facebook and industry-specific directories without manually checking each site. Beyond basic review generation, GatherUp includes Net Promoter Score (NPS) survey tooling for measuring and tracking customer sentiment over time, QR codes and custom feedback links for capturing feedback in physical locations, review widgets and automated social sharing so positive reviews can be redistributed as marketing content, and API access plus customer-list upload integrations so the review-request workflow can be triggered from a business's existing CRM or point-of-sale system. Two notable paid add-ons extend the core platform: Listings Hub, which syncs a business's name, address and phone information across roughly 125 online directories to keep local SEO listings consistent, and Review Defense, a tiered service focused on detecting and disputing fraudulent or policy-violating reviews. GatherUp's pricing is subscription-based and scales with the number of business locations being managed. The entry-level Small Business plan is priced at 99 dollars per month for a single location and includes 300 SMS credits and 3,000 email credits per month, full 100-plus site review monitoring, NPS surveys and AI-generated review response suggestions; a 14-day free trial is commonly offered to let prospective customers evaluate the platform before committing. For businesses managing multiple locations, pricing drops on a per-location basis; reported figures show plans starting around 60 dollars per location per month for the 2-10 location tier, with further volume discounts available down to roughly 25 dollars per location per month for very large multi-location portfolios of 100-plus locations, reflecting the platform's dual focus on both single-location small businesses and large franchise or multi-brand operators. Agencies that want to resell reputation management services to their own clients under their own branding can access a separate white-label Agency plan, priced on a custom quote basis rather than published rate cards. GatherUp's competitive set spans several overlapping categories of reputation-management and customer-experience software. Birdeye and Podium are its most direct competitors, both offering broadly similar review generation, messaging and reputation-monitoring feature sets aimed at the same local-business and franchise market; Reputation.com competes more at the large-enterprise end of the market with heavier emphasis on social listening and broader brand reputation; and Yext competes primarily on the listings-management side that GatherUp addresses through its Listings Hub add-on. Within the Traject portfolio itself, Grade.us serves a similar reputation-management use case and is positioned more toward marketing agencies specifically, giving Traject two related but differently-targeted products in the same broad category. The realistic target audience for GatherUp spans single-location small businesses that want a straightforward, done-for-you review generation workflow; multi-location brands and franchise groups that need centralized reputation reporting across dozens or hundreds of locations with per-location cost efficiency; and marketing agencies that want to offer white-label reputation management as a service line to their own client base. Businesses primarily looking for the cheapest possible entry point may find GatherUp's 99 dollar per month starting price higher than some lighter-weight review-request tools, but the trade-off is a more complete feature set spanning surveys, listings and fraud-detection add-ons within a single connected platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cb4b68ba-b4d4-4c0f-8fd7-b849bda16445';

